import { useState, useEffect, useRef } from 'react'
import { useSettingsStore } from '../stores/useSettingsStore'
import { useConfig, useProxyStatus, useAvailableFonts } from '../hooks/useIpc'
import { useOptimisticConfig } from '../hooks/useOptimisticConfig'
import { useAuth } from '../hooks/useIpc'
import type { ConfigKey, ConfigValueMap, FontInfo, ProxyStatus } from '@shared/types'
import { AppearanceSettings } from '../components/settings/AppearanceSettings'
import { DownloadSettings } from '../components/settings/DownloadSettings'
import { AuthSettings } from '../components/settings/AuthSettings'
import { ProxySettings } from '../components/settings/ProxySettings'
import { NotificationSettings } from '../components/settings/NotificationSettings'
import { TagFilterSettings } from '../components/settings/TagFilterSettings'
import { Toast } from '../components/common/Toast'
import { CacheSettings } from '../components/settings/CacheSettings'
import { MigrationDialog } from '../components/settings/MigrationDialog'
import { useMigration } from '../hooks/useMigration'

type CardStyle = 'cover' | 'detailed'
type OutputFormat = 'folder' | 'zip' | 'cbz'
type NotifyWhenForeground = 'inactive' | 'always'

interface ConfigState {
  downloadDir: string
  concurrentDownloads: number
  timeout: number
  retryTimes: number
  cbzFilenameTemplate: string
  batchDownloadDelay: number
  autoRetryMaxAttempts: number
  notifyOnComplete: boolean
  notifyWhenForeground: NotifyWhenForeground
  defaultSource: string
  previewCacheSizeLimitMB: number
}

interface SettingsPageProps {
  scrollTarget?: string | null
  onScrollDone?: () => void
}

export function SettingsPage({ scrollTarget, onScrollDone }: SettingsPageProps) {
  const { themeMode, cardStyle, sfwMode, setThemeMode, setCardStyle, setSfwMode, tagBlacklist, addTag, removeTag } = useSettingsStore()
  const loginSectionRef = useRef<HTMLDivElement>(null!)
  const { getConfig, setConfig, openDownloadDir, selectDirectory } = useConfig()
  const { applyAuth, verifyAuth } = useAuth()
  const { getProxyStatus } = useProxyStatus()
  const { getAvailableFonts } = useAvailableFonts()
  const [loginStatus, setLoginStatus] = useState<'idle' | 'verifying' | 'valid' | 'invalid' | 'error'>('idle')
  const [loginMessage, setLoginMessage] = useState('')
  const [outputFormat, setOutputFormat] = useState<OutputFormat>('cbz')
  const [config, setConfigState] = useState<ConfigState>({
    downloadDir: '',
    concurrentDownloads: 4,
    timeout: 30,
    retryTimes: 3,
    cbzFilenameTemplate: '{author}-{title}.cbz',
    batchDownloadDelay: 1,
    autoRetryMaxAttempts: 2,
    notifyOnComplete: true,
    notifyWhenForeground: 'inactive',
    defaultSource: 'hcomic',
    previewCacheSizeLimitMB: 500,
  })
  const [isSaving, setIsSaving] = useState(false)
  const [saveError, setSaveError] = useState<string | null>(null)
  const [availableFonts, setAvailableFonts] = useState<FontInfo[]>([])
  const [fontName, setFontName] = useState('')
  const [fontSize, setFontSize] = useState(14)
  const [proxyStatus, setProxyStatus] = useState<ProxyStatus | null>(null)
  const [proxyLoading, setProxyLoading] = useState(false)
  const [showLoginToast, setShowLoginToast] = useState(false)
  const { createHandler } = useOptimisticConfig(setConfig, setSaveError, setIsSaving)
  const [isMigrationOpen, setIsMigrationOpen] = useState(false)
  const migrationHook = useMigration()

  const SECTIONS = [
    { id: 'appearance', label: '外观设置', icon: '🎨' },
    { id: 'download',   label: '下载设置', icon: '📥' },
    { id: 'source',     label: '来源',     icon: '🌐' },
    { id: 'tag-filter', label: '标签过滤', icon: '🏷️' },
    { id: 'auth',       label: '认证设置', icon: '🔑' },
    { id: 'proxy',      label: '代理设置', icon: '🔌' },
    { id: 'notification', label: '通知设置', icon: '🔔' },
    { id: 'cache',      label: '缓存管理', icon: '💾' },
  ] as const

  const [activeSection, setActiveSection] = useState<string | null>(null)

  const loadProxyStatus = async () => {
    setProxyLoading(true)
    try {
      const result = await getProxyStatus()
      setProxyStatus(result)
    } catch {
      setProxyStatus(null)
    } finally {
      setProxyLoading(false)
    }
  }

  const loadConfig = async () => {
    try {
      const result = await getConfig()
      if (result.config) {
        setConfigState({
          downloadDir: result.config.downloadDir ?? '',
          concurrentDownloads: result.config.concurrentDownloads ?? 4,
          timeout: result.config.timeout ?? 30,
          retryTimes: result.config.retryTimes ?? 3,
          cbzFilenameTemplate: result.config.cbzFilenameTemplate ?? '{author}-{title}.cbz',
          batchDownloadDelay: result.config.batchDownloadDelay ?? 1,
          autoRetryMaxAttempts: result.config.autoRetryMaxAttempts ?? 2,
          notifyOnComplete: result.config.notifyOnComplete !== false,
          notifyWhenForeground: result.config.notifyWhenForeground ?? 'inactive',
          defaultSource: result.config.defaultSource ?? 'hcomic',
          previewCacheSizeLimitMB: result.config.previewCacheSizeLimitMB ?? 500,
        })
        if (result.config.outputFormat) {
          setOutputFormat(result.config.outputFormat as OutputFormat)
        }
        if (result.config.themeMode === 'light' || result.config.themeMode === 'dark' || result.config.themeMode === 'auto') {
          setThemeMode(result.config.themeMode)
        }
        if (result.config.hasAuth) {
          setLoginStatus('verifying')
          try {
            const verifyResult = await verifyAuth()
            setLoginStatus(verifyResult.valid ? 'valid' : 'invalid')
            setLoginMessage(verifyResult.message || '')
          } catch {
            setLoginStatus('idle')
          }
        }
        if (result.config.fontName) setFontName(result.config.fontName)
        if (result.config.fontSize) setFontSize(result.config.fontSize)
        if (typeof result.config.previewCacheSizeLimitMB === 'number') {
          setConfigState(prev => ({ ...prev, previewCacheSizeLimitMB: result.config.previewCacheSizeLimitMB }))
        }
      }
    } catch (err) {
      console.error('Failed to load config:', err)
    }
  }

  useEffect(() => {
    loadConfig()
  }, [])

  useEffect(() => {
    if (scrollTarget === 'login' && loginSectionRef.current) {
      loginSectionRef.current.scrollIntoView({ behavior: 'smooth', block: 'start' })
      onScrollDone?.()
    }
  }, [scrollTarget, onScrollDone])

  useEffect(() => {
    getAvailableFonts().then((result) => setAvailableFonts(result.fonts)).catch(() => {})
    loadProxyStatus()
  }, [getAvailableFonts, loadProxyStatus])

  useEffect(() => {
    let timer: ReturnType<typeof setTimeout> | null = null
    const unsubscribe = window.hcomic?.onLoginCookieSuccess(() => {
      setShowLoginToast(true)
      if (timer) clearTimeout(timer)
      timer = setTimeout(() => setShowLoginToast(false), 3000)
    })
    return () => {
      unsubscribe?.()
      if (timer) clearTimeout(timer)
    }
  }, [])

  const handleThemeChange = createHandler('themeMode', () => themeMode, setThemeMode, (prev) => setThemeMode(prev))

  const handleCardStyleChange = (style: CardStyle) => {
    setCardStyle(style)
  }

  const handleSfwModeChange = createHandler('sfwMode', () => sfwMode, setSfwMode, (prev) => setSfwMode(prev))

  const handleOutputFormatChange = createHandler('outputFormat', () => outputFormat, setOutputFormat, (prev) => setOutputFormat(prev))

  const handleConfigChange = async (key: ConfigKey, value: unknown) => {
    setSaveError(null)
    const prevValue = (config as Record<string, unknown>)[key]
    setConfigState(prev => ({ ...prev, [key]: value }))
    setIsSaving(true)
    try {
      await setConfig(key, value as ConfigValueMap[ConfigKey])
    } catch (err: unknown) {
      setConfigState(prev => ({ ...prev, [key]: prevValue }))
      setSaveError((err instanceof Error ? err.message : String(err)) || '保存失败')
      setTimeout(() => setSaveError(null), 5000)
    } finally {
      setIsSaving(false)
    }
  }

  const handleTextConfigChange = (key: ConfigKey, value: string) => {
    setSaveError(null)
    setConfigState(prev => ({ ...prev, [key]: value }))
  }

  const handleTextConfigBlur = async (key: ConfigKey) => {
    const value = (config as Record<string, unknown>)[key]
    setIsSaving(true)
    try {
      await setConfig(key, value as ConfigValueMap[ConfigKey])
    } catch (err: unknown) {
      try {
        const result = await getConfig()
        if (result.config) {
          const restored = (result.config as Record<string, unknown>)[key]
          if (restored !== undefined) {
            setConfigState(prev => ({ ...prev, [key]: restored }))
          }
        }
      } catch { /* reload 也失败则只显示错误 */ }
      setSaveError((err instanceof Error ? err.message : String(err)) || '保存失败')
      setTimeout(() => setSaveError(null), 5000)
    } finally {
      setIsSaving(false)
    }
  }

  const handleApplyAuth = async (curlText: string) => {
    if (!curlText.trim()) return
    setLoginStatus('verifying')
    setLoginMessage('')
    try {
      await applyAuth(curlText.trim())
      const verifyResult = await verifyAuth()
      setLoginStatus(verifyResult.valid ? 'valid' : 'invalid')
      setLoginMessage(verifyResult.message || '')
    } catch (err: unknown) {
      setLoginStatus('error')
      setLoginMessage((err instanceof Error ? err.message : String(err)) || '操作失败')
    }
  }

  const handleTestAuth = async () => {
    setLoginStatus('verifying')
    setLoginMessage('')
    try {
      const verifyResult = await verifyAuth()
      setLoginStatus(verifyResult.valid ? 'valid' : 'invalid')
      setLoginMessage(verifyResult.message || '')
    } catch (err: unknown) {
      setLoginStatus('error')
      setLoginMessage((err instanceof Error ? err.message : String(err)) || '验证失败')
    }
  }

  const handleOpenLoginWindow = async () => {
    const prevStatus = loginStatus
    setLoginStatus('verifying')
    setLoginMessage('')
    try {
      const result = await window.hcomic?.openLoginWindow()
      if (!result) {
        setLoginStatus(prevStatus)
        return
      }
      if (result.success) {
        setLoginStatus('valid')
        setLoginMessage(result.message || '登录成功')
      } else {
        if (result.message === '已取消') {
          setLoginStatus(prevStatus)
        } else {
          setLoginStatus('error')
          setLoginMessage(result.message || '登录失败')
        }
      }
    } catch (err: unknown) {
      setLoginStatus('error')
      setLoginMessage((err instanceof Error ? err.message : '') || '登录失败')
    }
  }

  const handleSectionClick = (sectionId: string) => {
    setActiveSection(sectionId)
    document.getElementById(`section-${sectionId}`)?.scrollIntoView({ behavior: 'smooth', block: 'start' })
    setTimeout(() => setActiveSection(null), 1500)
  }

  return (
    <div className="flex gap-0 max-w-5xl">
      {/* Sidebar */}
      <div className="w-[150px] shrink-0">
        <nav className="sticky top-6 space-y-0.5 pr-3">
          <div className="px-3 py-2 text-xs font-semibold text-[var(--text-secondary)] tracking-wide">
            设置区域
          </div>
          {SECTIONS.map((section) => (
            <button
              key={section.id}
              onClick={() => handleSectionClick(section.id)}
              className={`w-full text-left px-3 py-2 rounded-lg text-sm transition-colors
                ${activeSection === section.id
                  ? 'bg-[var(--accent)] text-white'
                  : 'text-[var(--text-primary)] hover:bg-[var(--bg-secondary)]'
                }`}
            >
              <span className="mr-2">{section.icon}</span>
              {section.label}
            </button>
          ))}
        </nav>
      </div>

      {/* Content */}
      <div className="flex-1 min-w-0 space-y-6">
      <Toast message="已成功获取" visible={showLoginToast} />
      <div className="flex items-center justify-between">
        <h2 className="text-lg font-semibold text-[var(--text-primary)]">设置</h2>
        <div className="flex items-center gap-2">
          {saveError && (
            <span className="text-sm text-red-500">{saveError}</span>
          )}
          {isSaving && (
            <span className="text-sm text-[var(--text-secondary)]">保存中...</span>
          )}
        </div>
      </div>

      {migrationHook.isActive && (
        <div className="bg-[var(--accent)]/10 border border-[var(--accent)] rounded-xl px-6 py-4 flex items-center gap-4">
          <div className="flex-1 min-w-0">
            <p className="text-sm font-medium text-[var(--text-primary)]">
              正在后台迁移漫画库 ({migrationHook.progress?.completed ?? 0}/{migrationHook.progress?.total ?? 0})
            </p>
            <div className="w-full h-1.5 bg-[var(--bg-secondary)] rounded-full mt-2 overflow-hidden">
              <div
                className="h-full bg-[var(--accent)] rounded-full transition-all duration-300"
                style={{
                  width: `${migrationHook.progress && migrationHook.progress.total > 0
                    ? Math.round((migrationHook.progress.completed / migrationHook.progress.total) * 100) : 0}%`
                }}
              />
            </div>
          </div>
          <button
            onClick={() => setIsMigrationOpen(true)}
            className="px-3 py-1.5 text-sm rounded-lg bg-[var(--accent)] text-white whitespace-nowrap"
          >
            查看详情
          </button>
        </div>
      )}

      <div id="section-appearance">
        <AppearanceSettings
          themeMode={themeMode}
          cardStyle={cardStyle}
          sfwMode={sfwMode}
          availableFonts={availableFonts}
          fontName={fontName}
          fontSize={fontSize}
          onThemeChange={handleThemeChange}
          onCardStyleChange={handleCardStyleChange}
          onSfwModeChange={handleSfwModeChange}
          onFontNameChange={setFontName}
          onFontSizeChange={setFontSize}
          setConfig={setConfig}
          setSaveError={setSaveError}
          setIsSaving={setIsSaving}
        />
      </div>

      <div id="section-download">
        <DownloadSettings
          outputFormat={outputFormat}
          config={{
            downloadDir: config.downloadDir,
            concurrentDownloads: config.concurrentDownloads,
            timeout: config.timeout,
            retryTimes: config.retryTimes,
            cbzFilenameTemplate: config.cbzFilenameTemplate,
            batchDownloadDelay: config.batchDownloadDelay,
          }}
          onOutputFormatChange={handleOutputFormatChange}
          onConfigChange={handleConfigChange}
          onTextConfigChange={handleTextConfigChange}
          onTextConfigBlur={handleTextConfigBlur}
          openDownloadDir={openDownloadDir}
          onSelectDirectory={async () => {
            const result = await selectDirectory('选择下载目录', config.downloadDir || undefined)
            if (!result.canceled && result.filePaths.length > 0) {
              handleConfigChange('downloadDir', result.filePaths[0])
            }
          }}
          setSaveError={setSaveError}
          onOpenMigration={() => setIsMigrationOpen(true)}
        />
      </div>

      <div id="section-source">
        <div className="bg-[var(--bg-primary)] rounded-xl p-6 shadow-sm space-y-6">
          <h3 className="text-base font-medium text-[var(--text-primary)] border-b border-[var(--border)] pb-3">
            来源
          </h3>

          <div>
            <label className="block text-sm font-medium text-[var(--text-primary)] mb-2">默认来源</label>
            <div className="flex gap-3">
              {['hcomic', 'moeimg'].map((source) => (
                <button
                  key={source}
                  onClick={() => handleConfigChange('defaultSource', source)}
                  className={`px-4 py-2 rounded-lg text-sm transition-colors ${
                    config.defaultSource === source
                      ? 'bg-[var(--accent)] text-white'
                      : 'bg-[var(--bg-secondary)] text-[var(--text-primary)] hover:bg-[var(--border)]'
                  }`}
                >
                  {source === 'hcomic' ? 'HComic' : 'Moeimg'}
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div id="section-tag-filter">
        <TagFilterSettings
          tagBlacklist={tagBlacklist}
          addTag={addTag}
          removeTag={removeTag}
        />
      </div>

      <div id="section-auth">
        <AuthSettings
          loginSectionRef={loginSectionRef}
          loginStatus={loginStatus}
          loginMessage={loginMessage}
          onApplyAuth={handleApplyAuth}
          onTestAuth={handleTestAuth}
          onOpenLoginWindow={handleOpenLoginWindow}
        />
      </div>

      <div id="section-proxy">
        <ProxySettings
          proxyStatus={proxyStatus}
          proxyLoading={proxyLoading}
          onRefresh={loadProxyStatus}
        />
      </div>

      <div id="section-notification">
        <NotificationSettings
          notifyOnComplete={config.notifyOnComplete}
          notifyWhenForeground={config.notifyWhenForeground}
          onConfigChange={handleConfigChange}
        />
      </div>

      <div id="section-cache">
        <CacheSettings
          sizeLimitMB={config.previewCacheSizeLimitMB}
          onSizeLimitChange={(mb) => handleConfigChange('previewCacheSizeLimitMB', mb)}
        />
      </div>

        <MigrationDialog
          isOpen={isMigrationOpen}
          onClose={() => setIsMigrationOpen(false)}
          currentDownloadDir={config.downloadDir}
          onSelectDirectory={selectDirectory}
        />
      </div>
    </div>
  )
}

// @vitest-environment node
import { describe, it, expect, vi, beforeEach } from 'vitest'

const { mockNotification } = vi.hoisted(() => {
  const mockNotify = vi.fn().mockImplementation(function (this: unknown, _opts: unknown) {
    return { on: vi.fn(), show: vi.fn() }
  })
  mockNotify.isSupported = vi.fn().mockReturnValue(true)
  return { mockNotification: mockNotify }
})

vi.mock('electron', () => ({
  app: { getName: vi.fn().mockReturnValue('TestApp') },
  Notification: mockNotification,
  BrowserWindow: vi.fn(),
}))

import { NotificationManager } from '../../../electron/notification-manager'

describe('NotificationManager', () => {
  let manager: NotificationManager
  let mockMainWindow: { isFocused: ReturnType<typeof vi.fn>; isMinimized: ReturnType<typeof vi.fn>; restore: ReturnType<typeof vi.fn>; show: ReturnType<typeof vi.fn>; focus: ReturnType<typeof vi.fn> }

  beforeEach(() => {
    vi.clearAllMocks()
    mockNotification.mockImplementation(function (this: unknown, _opts: unknown) {
      return { on: vi.fn(), show: vi.fn() }
    })
    mockNotification.isSupported.mockReturnValue(true)
    manager = new NotificationManager()
    mockMainWindow = {
      isFocused: vi.fn().mockReturnValue(false),
      isMinimized: vi.fn().mockReturnValue(false),
      restore: vi.fn(),
      show: vi.fn(),
      focus: vi.fn(),
    }
    manager.setMainWindow(mockMainWindow as unknown as Parameters<typeof manager.setMainWindow>[0])
    manager.updateSettings(true, 'inactive')
  })

  describe('handleProgress — task tracking', () => {
    it('tracks active tasks', () => {
      manager.handleProgress({ taskId: 't1', status: 'downloading', title: 'A' })
      manager.handleProgress({ taskId: 't2', status: 'queued', title: 'B' })
      expect(mockNotification).not.toHaveBeenCalled()
    })

    it('removes tasks when they complete or fail', () => {
      manager.handleProgress({ taskId: 't1', status: 'downloading', title: 'A' })
      manager.handleProgress({ taskId: 't1', status: 'completed', title: 'A' })
      expect(mockNotification).toHaveBeenCalledTimes(1)
    })

    it('tracks paused and pausing as active', () => {
      manager.handleProgress({ taskId: 't1', status: 'paused', title: 'A' })
      manager.handleProgress({ taskId: 't2', status: 'pausing', title: 'B' })
      expect(mockNotification).not.toHaveBeenCalled()
    })
  })

  describe('batch notification trigger', () => {
    it('sends notification when all active tasks complete', () => {
      manager.handleProgress({ taskId: 't1', status: 'downloading', title: 'A' })
      manager.handleProgress({ taskId: 't1', status: 'completed', title: 'A' })
      expect(mockNotification).toHaveBeenCalledTimes(1)
      expect(mockNotification).toHaveBeenCalledWith({
        title: 'TestApp',
        body: '下载完成：A',
      })
    })

    it('waits until all active tasks are done', () => {
      manager.handleProgress({ taskId: 't1', status: 'downloading', title: 'A' })
      manager.handleProgress({ taskId: 't2', status: 'completed', title: 'B' })
      expect(mockNotification).not.toHaveBeenCalled()

      manager.handleProgress({ taskId: 't1', status: 'completed', title: 'A' })
      expect(mockNotification).toHaveBeenCalledTimes(1)
    })

    it('batches multiple completions into one notification', () => {
      manager.handleProgress({ taskId: 't1', status: 'downloading', title: 'A' })
      manager.handleProgress({ taskId: 't2', status: 'downloading', title: 'B' })
      manager.handleProgress({ taskId: 't1', status: 'completed', title: 'A' })
      manager.handleProgress({ taskId: 't2', status: 'completed', title: 'B' })
      expect(mockNotification).toHaveBeenCalledTimes(1)
      expect(mockNotification).toHaveBeenCalledWith({
        title: 'TestApp',
        body: '批量下载完成：成功 2 本',
      })
    })

    it('includes failed tasks in batch body', () => {
      manager.handleProgress({ taskId: 't1', status: 'downloading', title: 'A' })
      manager.handleProgress({ taskId: 't2', status: 'downloading', title: 'B' })
      manager.handleProgress({ taskId: 't1', status: 'completed', title: 'A' })
      manager.handleProgress({ taskId: 't2', status: 'failed', title: 'B' })
      expect(mockNotification).toHaveBeenCalledWith({
        title: 'TestApp',
        body: '批量下载完成：成功 1 本，失败 1 本',
      })
    })
  })

  describe('notifyOnComplete = false', () => {
    it('does not send any notification', () => {
      manager.updateSettings(false, 'inactive')
      manager.handleProgress({ taskId: 't1', status: 'completed', title: 'A' })
      expect(mockNotification).not.toHaveBeenCalled()
    })
  })

  describe('notifyWhenForeground = inactive', () => {
    it('suppresses notification when window is focused', () => {
      mockMainWindow.isFocused.mockReturnValue(true)
      manager.handleProgress({ taskId: 't1', status: 'completed', title: 'A' })
      expect(mockNotification).not.toHaveBeenCalled()
    })

    it('sends notification when window is not focused', () => {
      mockMainWindow.isFocused.mockReturnValue(false)
      manager.handleProgress({ taskId: 't1', status: 'completed', title: 'A' })
      expect(mockNotification).toHaveBeenCalledTimes(1)
    })
  })

  describe('notifyWhenForeground = always', () => {
    it('sends notification even when window is focused', () => {
      manager.updateSettings(true, 'always')
      mockMainWindow.isFocused.mockReturnValue(true)
      manager.handleProgress({ taskId: 't1', status: 'completed', title: 'A' })
      expect(mockNotification).toHaveBeenCalledTimes(1)
    })
  })

  describe('Notification.isSupported = false', () => {
    it('does not send notification', () => {
      mockNotification.isSupported.mockReturnValue(false)
      manager.handleProgress({ taskId: 't1', status: 'completed', title: 'A' })
      expect(mockNotification).not.toHaveBeenCalled()
    })
  })

  describe('getter properties', () => {
    it('exposes current notifyOnComplete value', () => {
      expect(manager.notifyOnCompleteValue).toBe(true)
      manager.updateSettings(false, 'inactive')
      expect(manager.notifyOnCompleteValue).toBe(false)
    })

    it('exposes current notifyWhenForeground value', () => {
      expect(manager.notifyWhenForegroundValue).toBe('inactive')
      manager.updateSettings(true, 'always')
      expect(manager.notifyWhenForegroundValue).toBe('always')
    })
  })
})

// @vitest-environment node
import { describe, it, expect, beforeEach, vi } from 'vitest'

// Use vi.hoisted to create mock functions accessible in hoisted vi.mock factories
const { mockSpawn } = vi.hoisted(() => ({
  mockSpawn: vi.fn()
}))

vi.mock('child_process', async (importOriginal) => {
  const actual = await importOriginal() as Record<string, unknown>
  return {
    ...actual,
    spawn: mockSpawn
  }
})

// Mock electron
vi.mock('electron', () => ({
  app: {
    getPath: vi.fn().mockReturnValue('/mock/path'),
    getAppPath: vi.fn().mockReturnValue('/mock/project'),
    isPackaged: false
  }
}))

// Must import after mocks are set up
import { PythonBridge, getPythonBridge } from '../../../electron/python-bridge'

describe('PythonBridge', () => {
  let mockProcess: Record<string, unknown>
  let stdoutCallbacks: ((...args: unknown[]) => unknown)[]
  let stderrCallbacks: ((...args: unknown[]) => unknown)[]
  let exitCallbacks: ((...args: unknown[]) => unknown)[]
  let errorCallbacks: ((...args: unknown[]) => unknown)[]
  let stdinWriteData: string[]

  beforeEach(() => {
    mockSpawn.mockClear()
    stdoutCallbacks = []
    stderrCallbacks = []
    exitCallbacks = []
    errorCallbacks = []
    stdinWriteData = []

    mockProcess = {
      stdin: {
        write: vi.fn((data: string) => {
          stdinWriteData.push(data)
        }),
        writable: true
      },
      stdout: {
        on: vi.fn((event: string, cb: (...args: unknown[]) => unknown) => {
          if (event === 'data') stdoutCallbacks.push(cb)
        }),
        removeAllListeners: vi.fn()
      },
      stderr: {
        on: vi.fn((event: string, cb: (...args: unknown[]) => unknown) => {
          if (event === 'data') stderrCallbacks.push(cb)
        }),
        removeAllListeners: vi.fn()
      },
      on: vi.fn((event: string, cb: (...args: unknown[]) => unknown) => {
        if (event === 'exit') exitCallbacks.push(cb)
        if (event === 'error') errorCallbacks.push(cb)
      }),
      kill: vi.fn(),
      removeAllListeners: vi.fn()
    }

    mockSpawn.mockReturnValue(mockProcess)
  })

  describe('constructor and spawn', () => {
    it('should spawn python process with correct path in dev mode', () => {
      new PythonBridge()

      expect(mockSpawn).toHaveBeenCalledTimes(1)
      expect(mockSpawn).toHaveBeenCalledWith('python', [expect.stringContaining('ipc_server.py')], expect.objectContaining({
        stdio: ['pipe', 'pipe', 'pipe'],
        windowsHide: true,
        env: expect.objectContaining({ PYTHONIOENCODING: 'utf-8' }),
      }))
    })

    it('should set up stdout, stderr, exit and error listeners', () => {
      new PythonBridge()

      expect(mockProcess.stdout.on).toHaveBeenCalledWith('data', expect.any(Function))
      expect(mockProcess.stderr.on).toHaveBeenCalledWith('data', expect.any(Function))
      expect(mockProcess.on).toHaveBeenCalledWith('exit', expect.any(Function))
      expect(mockProcess.on).toHaveBeenCalledWith('error', expect.any(Function))
    })
  })

  describe('call()', () => {
    let bridge: PythonBridge

    beforeEach(() => {
      bridge = new PythonBridge()
    })

    it('should send JSON-RPC formatted request via stdin', async () => {
      const callPromise = bridge.call('search', { query: 'test', mode: 'title', page: 1 })

      // Capture what was written to stdin
      expect(stdinWriteData.length).toBe(1)
      const written = JSON.parse(stdinWriteData[0].trim())
      expect(written).toMatchObject({
        jsonrpc: '2.0',
        method: 'search',
        params: { query: 'test', mode: 'title', page: 1 }
      })
      expect(written.id).toBeDefined()
      expect(typeof written.id).toBe('string')

      // Simulate response to resolve the promise (prevent unhandled rejection)
      const response = { jsonrpc: '2.0', id: written.id, result: { data: 'ok' } }
      stdoutCallbacks.forEach(cb => cb(Buffer.from(JSON.stringify(response) + '\n')))

      await callPromise
    })

    it('should resolve when stdout returns matching response', async () => {
      const callPromise = bridge.call('get_config')
      const written = JSON.parse(stdinWriteData[0].trim())
      const requestId = written.id

      // Simulate response
      const response = { jsonrpc: '2.0', id: requestId, result: { theme: 'dark' } }
      stdoutCallbacks.forEach(cb => cb(Buffer.from(JSON.stringify(response) + '\n')))

      const result = await callPromise
      expect(result).toEqual({ theme: 'dark' })
    })

    it('should reject on error response', async () => {
      const callPromise = bridge.call('search', { query: 'test' })
      const written = JSON.parse(stdinWriteData[0].trim())
      const requestId = written.id

      // Simulate error response
      const response = { jsonrpc: '2.0', id: requestId, error: { message: 'Search failed' } }
      stdoutCallbacks.forEach(cb => cb(Buffer.from(JSON.stringify(response) + '\n')))

      await expect(callPromise).rejects.toThrow('Search failed')
    })

    it('should reject pending requests when process exits', async () => {
      const callPromise = bridge.call('search', { query: 'test' })

      // Simulate process exit while request is pending
      exitCallbacks.forEach(cb => cb(1))

      await expect(callPromise).rejects.toThrow('Python process exited with code 1')
    })

    it('should reject with "Python process not running" when calling after process exits', async () => {
      // Simulate process exit
      exitCallbacks.forEach(cb => cb(0))

      await expect(bridge.call('search')).rejects.toThrow('Python process not running')
    })

    it('should reject when process was killed before call', async () => {
      bridge.kill()

      await expect(bridge.call('search')).rejects.toThrow('Python process not running')
    })

    it('should time out after 30 seconds', async () => {
      vi.useFakeTimers()

      const callPromise = bridge.call('search', { query: 'test' })

      // Advance time by 30 seconds
      vi.advanceTimersByTime(30000)

      await expect(callPromise).rejects.toThrow('Request timeout')

      vi.useRealTimers()
    })

    it('should not resolve with stale response after timeout', async () => {
      vi.useFakeTimers()

      const callPromise = bridge.call('search', { query: 'test' })
      const written = JSON.parse(stdinWriteData[0].trim())
      const requestId = written.id

      // Trigger timeout
      vi.advanceTimersByTime(30000)

      // Late response arrives after timeout - should be ignored
      const response = { jsonrpc: '2.0', id: requestId, result: { data: 'late' } }
      stdoutCallbacks.forEach(cb => cb(Buffer.from(JSON.stringify(response) + '\n')))

      await expect(callPromise).rejects.toThrow('Request timeout')

      vi.useRealTimers()
    })

    it('should handle multiple concurrent calls independently', async () => {
      const call1 = bridge.call('search', { query: 'test1' })
      const call2 = bridge.call('search', { query: 'test2' })

      const written1 = JSON.parse(stdinWriteData[0].trim())
      const written2 = JSON.parse(stdinWriteData[1].trim())

      // Respond to second call first (out of order)
      const response2 = { jsonrpc: '2.0', id: written2.id, result: { query: 'test2' } }
      stdoutCallbacks.forEach(cb => cb(Buffer.from(JSON.stringify(response2) + '\n')))

      const result2 = await call2
      expect(result2).toEqual({ query: 'test2' })

      // Then respond to first call
      const response1 = { jsonrpc: '2.0', id: written1.id, result: { query: 'test1' } }
      stdoutCallbacks.forEach(cb => cb(Buffer.from(JSON.stringify(response1) + '\n')))

      const result1 = await call1
      expect(result1).toEqual({ query: 'test1' })
    })

    it('should handle partial data received across multiple stdout events', async () => {
      const callPromise = bridge.call('get_config')
      const written = JSON.parse(stdinWriteData[0].trim())
      const requestId = written.id

      const response = { jsonrpc: '2.0', id: requestId, result: { ok: true } }
      const responseStr = JSON.stringify(response) + '\n'

      // Send first half
      const half = Math.floor(responseStr.length / 2)
      stdoutCallbacks.forEach(cb => cb(Buffer.from(responseStr.slice(0, half))))
      // Send second half
      stdoutCallbacks.forEach(cb => cb(Buffer.from(responseStr.slice(half))))

      const result = await callPromise
      expect(result).toEqual({ ok: true })
    })

    it('should ignore responses for unknown request IDs', async () => {
      const callPromise = bridge.call('get_config')
      const written = JSON.parse(stdinWriteData[0].trim())

      // Send response for a different, unknown ID
      const unknownResponse = { jsonrpc: '2.0', id: 'unknown-id', result: 'ignore' }
      stdoutCallbacks.forEach(cb => cb(Buffer.from(JSON.stringify(unknownResponse) + '\n')))

      // Now send the correct response
      const correctResponse = { jsonrpc: '2.0', id: written.id, result: { config: 'value' } }
      stdoutCallbacks.forEach(cb => cb(Buffer.from(JSON.stringify(correctResponse) + '\n')))

      const result = await callPromise
      expect(result).toEqual({ config: 'value' })
    })
  })

  describe('kill()', () => {
    it('should terminate the process', () => {
      const bridge = new PythonBridge()

      expect(mockSpawn).toHaveBeenCalledTimes(1)
      bridge.kill()

      expect(mockProcess.kill).toHaveBeenCalledTimes(1)
    })

    it('should not throw if called when no process exists', () => {
      const bridge = new PythonBridge()
      // Simulate exit
      exitCallbacks.forEach(cb => cb(0))

      // kill should not throw
      expect(() => bridge.kill()).not.toThrow()
    })

    it('should prevent further calls after kill', async () => {
      const bridge = new PythonBridge()
      bridge.kill()

      await expect(bridge.call('search')).rejects.toThrow('Python process not running')
    })

    it('should not auto-restart after explicit kill', () => {
      vi.useFakeTimers()
      const bridge = new PythonBridge()
      expect(mockSpawn).toHaveBeenCalledTimes(1)

      bridge.kill()
      vi.advanceTimersByTime(3000)

      // Should NOT have respawned
      expect(mockSpawn).toHaveBeenCalledTimes(1)
      vi.useRealTimers()
    })
  })

  describe('auto-restart', () => {
    it('should attempt restart after unexpected process exit', () => {
      vi.useFakeTimers()
      new PythonBridge()
      expect(mockSpawn).toHaveBeenCalledTimes(1)

      // Simulate unexpected exit
      exitCallbacks.forEach(cb => cb(1))
      vi.advanceTimersByTime(2000)

      expect(mockSpawn).toHaveBeenCalledTimes(2)
      vi.useRealTimers()
    })
  })

  describe('error handler', () => {
    it('should reject pending requests on process error', async () => {
      const bridge = new PythonBridge()
      const callPromise = bridge.call('search', { query: 'test' })

      errorCallbacks[errorCallbacks.length - 1](new Error('spawn ENOENT'))

      await expect(callPromise).rejects.toThrow('Python process error')
    })

    it('should null out process reference on error and not restart immediately', async () => {
      vi.useFakeTimers()
      const _bridge = new PythonBridge()
      errorCallbacks[errorCallbacks.length - 1](new Error('spawn ENOENT'))

      // Process should be null until restart timer fires
      expect(mockSpawn).toHaveBeenCalledTimes(1)
      vi.advanceTimersByTime(1000)
      // Still not restarted (2s delay)
      expect(mockSpawn).toHaveBeenCalledTimes(1)
      vi.useRealTimers()
    })

    it('should schedule restart after error', () => {
      vi.useFakeTimers()
      new PythonBridge()
      expect(mockSpawn).toHaveBeenCalledTimes(1)

      errorCallbacks[errorCallbacks.length - 1](new Error('spawn ENOENT'))
      vi.advanceTimersByTime(2000)

      expect(mockSpawn).toHaveBeenCalledTimes(2)
      vi.useRealTimers()
    })
  })

  describe('bounded restarts', () => {
    it('should stop restarting after max attempts', () => {
      vi.useFakeTimers()
      new PythonBridge()
      expect(mockSpawn).toHaveBeenCalledTimes(1)

      // Each restart creates a new process with new exit callbacks
      // Simulate exit + restart 5 times (reaching MAX_RESTARTS)
      for (let i = 0; i < 5; i++) {
        // Only fire the latest exit callback (from the latest process)
        const latestCb = exitCallbacks[exitCallbacks.length - 1]
        latestCb(1)
        vi.advanceTimersByTime(2000)
      }

      // 1 initial + 5 restarts = 6 total
      expect(mockSpawn).toHaveBeenCalledTimes(6)

      // One more exit should NOT trigger another restart
      const latestCb = exitCallbacks[exitCallbacks.length - 1]
      latestCb(1)
      vi.advanceTimersByTime(2000)
      expect(mockSpawn).toHaveBeenCalledTimes(6)
      vi.useRealTimers()
    })

    it('should reset restart count on successful response', async () => {
      vi.useFakeTimers()
      new PythonBridge()

      // First failure + restart
      exitCallbacks[exitCallbacks.length - 1](1)
      vi.advanceTimersByTime(2000)
      expect(mockSpawn).toHaveBeenCalledTimes(2)

      // Simulate successful response to reset counter
      const bridge = getPythonBridge()
      const callPromise = bridge.call('get_config')
      const written = JSON.parse(stdinWriteData[stdinWriteData.length - 1].trim())
      const response = { jsonrpc: '2.0', id: written.id, result: { ok: true } }
      stdoutCallbacks[stdoutCallbacks.length - 1](Buffer.from(JSON.stringify(response) + '\n'))
      await callPromise

      // Simulate more failures - should restart since counter was reset
      for (let i = 0; i < 3; i++) {
        exitCallbacks[exitCallbacks.length - 1](1)
        vi.advanceTimersByTime(2000)
      }

      expect(mockSpawn.mock.calls.length).toBeGreaterThan(2)
      vi.useRealTimers()
    })
  })

  describe('stdin writability check', () => {
    it('should throw immediately if stdin is not writable', async () => {
      const bridge = new PythonBridge()
      mockProcess.stdin.writable = false

      await expect(bridge.call('search')).rejects.toThrow('Python process stdin not writable')
    })
  })

  describe('call() race condition guard', () => {
    it('should reject if process is replaced between snapshot and write', async () => {
      const bridge = new PythonBridge()

      // Sabotage: make the first write throw to simulate process dying mid-call
      let writeCallCount = 0
      const _originalWrite = mockProcess.stdin.write
      mockProcess.stdin.write = vi.fn((data: string) => {
        writeCallCount++
        if (writeCallCount === 1) {
          // First call is from the constructor (bridge.call in get_config sync)
          // Let it succeed or just record it
        }
        stdinWriteData.push(data)
      })

      // Force process to null then back to simulate replacement
      // After killing, process is null; spawn creates a new one
      bridge.kill()

      await expect(bridge.call('search')).rejects.toThrow('Python process not running')
    })

    it('should catch stdin write errors gracefully', async () => {
      const bridge = new PythonBridge()

      // Make write throw
      mockProcess.stdin.write = vi.fn(() => {
        throw new Error('EPIPE')
      })

      await expect(bridge.call('search')).rejects.toThrow('Failed to write to Python process stdin')
    })
  })

  describe('buffer overflow protection', () => {
    it('should reject pending requests immediately when buffer overflows', async () => {
      const bridge = new PythonBridge()

      // Start a pending request first
      const callPromise = bridge.call('search', { query: 'test' })

      // Send >20MB of garbage without newline to trigger overflow
      const bigData = Buffer.from('x'.repeat(20 * 1024 * 1024 + 1))
      stdoutCallbacks.forEach(cb => cb(bigData))

      // The pending request should be rejected immediately, not after 30s timeout
      await expect(callPromise).rejects.toThrow('IPC response too large')
    })

    it('should kill old process on buffer overflow', () => {
      new PythonBridge()

      const bigData = Buffer.from('x'.repeat(20 * 1024 * 1024 + 1))
      stdoutCallbacks.forEach(cb => cb(bigData))

      expect(mockProcess.kill).toHaveBeenCalled()
    })

    it('should trigger restart after buffer overflow', () => {
      vi.useFakeTimers()
      new PythonBridge()
      expect(mockSpawn).toHaveBeenCalledTimes(1)

      // Trigger overflow - should call handleProcessFailure which schedules restart
      const bigData = Buffer.from('x'.repeat(20 * 1024 * 1024 + 1))
      stdoutCallbacks.forEach(cb => cb(bigData))

      vi.advanceTimersByTime(2000)
      expect(mockSpawn).toHaveBeenCalledTimes(2)
      vi.useRealTimers()
    })

    it('should ignore old stdout data after overflow and restart', () => {
      vi.useFakeTimers()
      new PythonBridge()

      // Trigger overflow — kills old process and schedules restart
      const bigData = Buffer.from('x'.repeat(20 * 1024 * 1024 + 1))
      stdoutCallbacks.forEach(cb => cb(bigData))

      expect(mockProcess.kill).toHaveBeenCalled()
      expect(mockProcess.stdout.removeAllListeners).toHaveBeenCalledWith('data')
      expect(mockProcess.stderr.removeAllListeners).toHaveBeenCalledWith('data')

      // Create a new mock process for the restart
      const mockProcess2 = {
        stdin: { write: vi.fn(), writable: true },
        stdout: { on: vi.fn(), removeAllListeners: vi.fn() },
        stderr: { on: vi.fn(), removeAllListeners: vi.fn() },
        on: vi.fn(),
        kill: vi.fn(),
        removeAllListeners: vi.fn(),
      }
      mockSpawn.mockReturnValue(mockProcess2)

      // Save old callback count before restart
      const oldStdoutCount = stdoutCallbacks.length

      // Advance time to trigger restart
      vi.advanceTimersByTime(2000)
      expect(mockSpawn).toHaveBeenCalledTimes(2)

      // Fire OLD stdout callbacks (not the new ones)
      for (let i = 0; i < oldStdoutCount; i++) {
        stdoutCallbacks[i](Buffer.from('garbage from old process\n'))
      }

      // New process must NOT be killed by old callbacks
      expect(mockProcess2.kill).not.toHaveBeenCalled()
      vi.useRealTimers()
    })
  })

  describe('getPythonBridge()', () => {
    it('should return a PythonBridge instance', () => {
      const bridge = getPythonBridge()
      expect(bridge).toBeInstanceOf(PythonBridge)
    })
  })
})

// @vitest-environment node
import { describe, it, expect } from 'vitest'
import {
  string, number, boolean, object, integer,
  minLength, maxLength, length, range, minValue,
  pattern, oneOf,
  and,
  noControlChars, noPathSeparators, noPathTraversal, absolutePath,
  tagBlacklist,
  assert,
  ValidationError,
} from '../../../electron/validators'

describe('validators.ts', () => {
  describe('atomic type validators', () => {
    it('string() passes for strings', () => {
      expect(string()('hello')).toBe(true)
    })

    it('string() throws for non-strings', () => {
      expect(() => string()(123)).toThrow(ValidationError)
      expect(() => string()(null)).toThrow(ValidationError)
      expect(() => string()(undefined)).toThrow(ValidationError)
    })

    it('number() passes for finite numbers', () => {
      expect(number()(42)).toBe(true)
      expect(number()(0)).toBe(true)
      expect(number()(-3.14)).toBe(true)
    })

    it('number() rejects NaN and Infinity', () => {
      expect(() => number()(NaN)).toThrow(ValidationError)
      expect(() => number()(Infinity)).toThrow(ValidationError)
    })

    it('number() rejects non-numbers', () => {
      expect(() => number()('42')).toThrow(ValidationError)
    })

    it('boolean() passes for booleans', () => {
      expect(boolean()(true)).toBe(true)
      expect(boolean()(false)).toBe(true)
    })

    it('boolean() rejects non-booleans', () => {
      expect(() => boolean()(0)).toThrow(ValidationError)
      expect(() => boolean()('true')).toThrow(ValidationError)
    })

    it('object() passes for non-null objects', () => {
      expect(object()({})).toBe(true)
      expect(object()({ a: 1 })).toBe(true)
    })

    it('object() rejects null and non-objects', () => {
      expect(() => object()(null)).toThrow(ValidationError)
      expect(() => object()(42)).toThrow(ValidationError)
      // Note: arrays pass object() since typeof [] === 'object' and !== null
      expect(object()([])).toBe(true)
    })

    it('integer() passes for integers', () => {
      expect(integer()(0)).toBe(true)
      expect(integer()(-1)).toBe(true)
      expect(integer()(42)).toBe(true)
    })

    it('integer() rejects non-integers', () => {
      expect(() => integer()(1.5)).toThrow(ValidationError)
      expect(() => integer()('1')).toThrow(ValidationError)
    })
  })

  describe('string constraint validators', () => {
    it('minLength passes when length >= min', () => {
      expect(minLength(3)('abc')).toBe(true)
      expect(minLength(3)('abcd')).toBe(true)
    })

    it('minLength throws when length < min', () => {
      expect(() => minLength(3)('ab')).toThrow(ValidationError)
    })

    it('maxLength passes when length <= max', () => {
      expect(maxLength(3)('abc')).toBe(true)
      expect(maxLength(3)('ab')).toBe(true)
    })

    it('maxLength throws when length > max', () => {
      expect(() => maxLength(3)('abcd')).toThrow(ValidationError)
    })

    it('length combines min and max', () => {
      expect(length(2, 5)('abc')).toBe(true)
      expect(length(2, 5)('a')).toBe(false) // and() catches errors, returns false
      expect(length(2, 5)('abcdef')).toBe(false)
    })
  })

  describe('number constraint validators', () => {
    it('range passes for values within range', () => {
      expect(range(0, 100)(50)).toBe(true)
      expect(range(0, 100)(0)).toBe(true)
      expect(range(0, 100)(100)).toBe(true)
    })

    it('range rejects values outside range', () => {
      expect(() => range(0, 100)(-1)).toThrow(ValidationError)
      expect(() => range(0, 100)(101)).toThrow(ValidationError)
    })

    it('minValue passes for values >= min', () => {
      expect(minValue(0)(0)).toBe(true)
      expect(minValue(0)(100)).toBe(true)
    })

    it('minValue rejects values < min', () => {
      expect(() => minValue(0)(-1)).toThrow(ValidationError)
    })
  })

  describe('pattern validators', () => {
    it('pattern passes for matching strings', () => {
      expect(pattern(/^abc$/)('abc')).toBe(true)
    })

    it('pattern rejects non-matching strings', () => {
      expect(() => pattern(/^abc$/)('abcd')).toThrow(ValidationError)
    })

    it('oneOf passes for allowed values', () => {
      expect(oneOf(['a', 'b', 'c'])('a')).toBe(true)
    })

    it('oneOf rejects disallowed values', () => {
      expect(() => oneOf(['a', 'b', 'c'])('d')).toThrow(ValidationError)
    })
  })

  describe('combinator: and()', () => {
    it('passes when all validators pass', () => {
      const v = and(string(), minLength(3), maxLength(10))
      expect(v('hello')).toBe(true)
    })

    it('returns false when a validator throws', () => {
      const v = and(string(), minLength(10))
      expect(v('hi')).toBe(false)
    })

    it('returns false when a validator returns false', () => {
      const alwaysFalse: (v: unknown) => v is string = (_v: unknown): _v is string => false
      const v = and(string(), alwaysFalse)
      expect(v('test')).toBe(false)
    })

    it('swallows specific error messages — returns only true/false', () => {
      const v = and(string(), minLength(5))
      // Should not throw — returns false
      expect(() => v('hi')).not.toThrow()
      expect(v('hi')).toBe(false)
    })
  })

  describe('security validators', () => {
    it('noControlChars rejects strings with control characters', () => {
      expect(noControlChars()('hello')).toBe(true)
      expect(() => noControlChars()('hel\x00lo')).toThrow(ValidationError)
      expect(() => noControlChars()('hel\x1flo')).toThrow(ValidationError)
    })

    it('noPathSeparators rejects strings with / or \\', () => {
      expect(noPathSeparators()('hello')).toBe(true)
      expect(() => noPathSeparators()('path/to/file')).toThrow(ValidationError)
      expect(() => noPathSeparators()('path\\to\\file')).toThrow(ValidationError)
    })

    it('noPathTraversal rejects strings with ..', () => {
      expect(noPathTraversal()('hello')).toBe(true)
      expect(() => noPathTraversal()('../etc')).toThrow(ValidationError)
      expect(() => noPathTraversal()('foo/../bar')).toThrow(ValidationError)
    })

    it('absolutePath accepts absolute paths', () => {
      expect(absolutePath()('C:\\Users\\test')).toBe(true)
      expect(absolutePath()('/home/user')).toBe(true)
      expect(absolutePath()('\\\\server\\share')).toBe(true)
    })

    it('absolutePath rejects relative paths', () => {
      expect(() => absolutePath()('relative/path')).toThrow(ValidationError)
      expect(() => absolutePath()('file.txt')).toThrow(ValidationError)
    })
  })

  describe('tagBlacklist()', () => {
    it('passes for valid tag blacklist', () => {
      const v = tagBlacklist()
      expect(v({ hcomic: ['tag1', 'tag2'], moeimg: [] })).toBe(true)
    })

    it('rejects non-object', () => {
      expect(() => tagBlacklist()(null)).toThrow(ValidationError)
      expect(() => tagBlacklist()('string')).toThrow(ValidationError)
    })

    it('rejects non-array values', () => {
      expect(() => tagBlacklist()({ hcomic: 'not-array', moeimg: [] })).toThrow(ValidationError)
    })

    it('rejects arrays exceeding 500 items', () => {
      const big = Array(501).fill('tag')
      expect(() => tagBlacklist()({ hcomic: big, moeimg: [] })).toThrow(ValidationError)
    })

    it('rejects empty strings', () => {
      expect(() => tagBlacklist()({ hcomic: [''], moeimg: [] })).toThrow(ValidationError)
    })

    it('rejects strings over 64 chars', () => {
      expect(() => tagBlacklist()({ hcomic: ['a'.repeat(65)], moeimg: [] })).toThrow(ValidationError)
    })

    it('rejects duplicates (case-insensitive)', () => {
      expect(() => tagBlacklist()({ hcomic: ['Tag', 'tag'], moeimg: [] })).toThrow(ValidationError)
    })

    it('accepts max 500 items', () => {
      const exact = Array(500).fill(0).map((_, i) => `tag${i}`)
      expect(tagBlacklist()({ hcomic: exact, moeimg: [] })).toBe(true)
    })
  })

  describe('assert()', () => {
    it('does not throw for valid values', () => {
      expect(() => assert(string(), 'hello', 'test')).not.toThrow()
    })

    it('throws ValidationError for invalid values', () => {
      expect(() => assert(string(), 123, 'test')).toThrow(ValidationError)
    })

    it('wraps error messages with label', () => {
      try {
        assert(string(), 123, 'myField')
      } catch (e) {
        expect(e).toBeInstanceOf(ValidationError)
        expect((e as ValidationError).message).toContain('myField')
      }
    })

    it('re-throws non-ValidationError exceptions', () => {
      const throws: (v: unknown) => v is string = (_v: unknown): _v is string => { throw new Error('custom') }
      expect(() => assert(throws, 'x', 'test')).toThrow('custom')
    })
  })
})
